  "landing.seeHowItWorks": { en: "See How It Works", zh: "了解運作方式", ko: "작동 방식 보기", ru: "Как это работает", de: "So funktioniert es", pt: "Veja como funciona", ja: "仕組みを見る", id: "Lihat Cara Kerjanya", fil: "Tingnan Kung Paano Gumagana" },
